sql:
SELECT average_rating, number_of_ratings
FROM provider_ratings
WHERE year_id = 0 AND county_id = 1;

SELECT SUM(total_patients_served) AS total_patients_served_all_counties
FROM provider_distribution
WHERE year_id = 1;

external_knowledge:
- A "county" refers to a geographic and administrative region in a country or state; 
- A "year" refers to a specific period of 365 or 366 days; 
- "Healthcare provider statistics" include the total number of providers and the average rating of these providers in a county; 
- "Rankings by patients served" and "rankings by average rating" refer to the positions of counties within a year based on the total number of patients served and the average rating of healthcare providers, respectively, with the top position being the highest value.

sql:
SELECT AVG(share) AS average_share
FROM provider_distribution
WHERE year_id = 2023;
